// Parallel TypeScript SDK — call client.monitor.* / client.taskRun.* /
// client.taskGroup.* directly. Requires NODE_FUNCTION_ALLOW_EXTERNAL=parallel-web
// on self-hosted n8n; n8n Cloud allowlists it for the procurement template.
const ParallelMod = require('parallel-web');
const Parallel = ParallelMod.default || ParallelMod;
const client = new Parallel({ apiKey: $vars.PARALLEL_API_KEY });

const monitorId = $json.monitor_id;
const eventGroupId = $json.event_group_id;
if (!monitorId || !eventGroupId) {
  throw new Error('Fetch Event Details: missing monitor_id or event_group_id.');
}
const page = await client.monitor.events(monitorId, { event_group_id: eventGroupId });
return [{ json: { ...$json, events: page.events || [] } }];

const data = $input.first().json;
const events = Array.isArray(data.events) ? data.events : [];
const entry = events.find(e => !e.event_type || e.event_type === 'event_stream');

let output = {};
let basis = [];
if (entry && entry.output) {
  basis = Array.isArray(entry.output.basis) ? entry.output.basis : [];
  const content = entry.output.content;
  if (entry.output.type === 'json' && content && typeof content === 'object') {
    output = content;
  } else if (entry.output.type === 'text' && typeof content === 'string') {
    output = { event_summary: content, severity: 'LOW', adverse: false, event_type: 'unknown' };
  }
}

const vendorContext = data.metadata || {};
return [{ json: {
  monitor_id: data.monitor_id,
  event_group_id: data.event_group_id,
  metadata: vendorContext,
  vendor: {
    vendor_name: vendorContext.vendor_name,
    vendor_domain: vendorContext.vendor_domain,
  },
  event_id: entry ? entry.event_id : null,
  event_date: entry ? entry.event_date : null,
  event_summary: output.event_summary || '',
  severity: output.severity || 'LOW',
  adverse: !!output.adverse,
  event_type: output.event_type || vendorContext.risk_dimension || 'unknown',
  basis,
  source: 'monitor_event',
  // Repeat dimension values at the top level so the inline scorer can
  // map them onto the dimensions schema for a single-dimension event.
  research_output: {
    [vendorContext.risk_dimension || 'event']: {
      status: output.severity || 'LOW',
      severity: output.severity || 'LOW',
      findings: output.event_summary || '',
    }
  },
  run_id: entry ? entry.event_id : data.event_group_id,
} }];

const payload = $input.first().json;
const vendor_name = (payload.text || '').trim();
if (!vendor_name) throw new Error('Vendor name is required. Usage: /vendor-research {vendor_name}');

const prompt = 'Conduct a comprehensive vendor risk assessment of "' + vendor_name + '". ' +
  'Investigate financial health, legal & regulatory, cybersecurity, leadership & governance, ESG & reputation. ' +
  'Classify each finding by severity (LOW/MEDIUM/HIGH/CRITICAL) and include source URLs.';

const outputSchema = {
  type: "json",
  json_schema: {
    type: "object",
    properties: {
      vendor_name: { type: "string" },
      overall_risk_level: { type: "string", enum: ["LOW","MEDIUM","HIGH","CRITICAL"] },
      financial_health: { type: "object", properties: { status: { type: "string" }, findings: { type: "string" }, severity: { type: "string" } } },
      legal_regulatory: { type: "object", properties: { status: { type: "string" }, findings: { type: "string" }, severity: { type: "string" } } },
      cybersecurity: { type: "object", properties: { status: { type: "string" }, findings: { type: "string" }, severity: { type: "string" } } },
      leadership_governance: { type: "object", properties: { status: { type: "string" }, findings: { type: "string" }, severity: { type: "string" } } },
      esg_reputation: { type: "object", properties: { status: { type: "string" }, findings: { type: "string" }, severity: { type: "string" } } },
      adverse_events: { type: "array", items: { type: "object" } },
      recommendation: { type: "string" },
    },
    required: ["vendor_name","overall_risk_level","recommendation"]
  }
};

return [{ json: {
  vendor_name,
  channel_id: payload.channel_id || payload.channel,
  user_name: payload.user_name || payload.user,
  response_url: payload.response_url,
  prompt,
  outputSchema,
} }];

// Parallel TypeScript SDK — call client.monitor.* / client.taskRun.* /
// client.taskGroup.* directly. Requires NODE_FUNCTION_ALLOW_EXTERNAL=parallel-web
// on self-hosted n8n; n8n Cloud allowlists it for the procurement template.
const ParallelMod = require('parallel-web');
const Parallel = ParallelMod.default || ParallelMod;
const client = new Parallel({ apiKey: $vars.PARALLEL_API_KEY });

const item = $json;
const run = await client.taskRun.create({
  input: item.prompt,
  processor: $vars.RESEARCH_PROCESSOR || 'ultra8x',
  task_spec: { output_schema: item.outputSchema },
  webhook: {
    url: ($vars.N8N_WEBHOOK_BASE_URL || '') + '/webhook/parallel-task-completion',
    event_types: ['task_run.status'],
  },
});
return [{ json: {
  vendor_name: item.vendor_name,
  channel_id: item.channel_id,
  user_name: item.user_name,
  run_id: run.run_id,
  status: run.status,
} }];

const d = $input.first().json;
const run_id = d.run_id || (d.data && d.data.run_id);
const status = d.status || (d.data && d.data.status);
if (status && status !== 'completed') {
  return [];
}
return [{ json: {
  ...d,
  run_id,
  status,
} }];

// Parallel TypeScript SDK — call client.monitor.* / client.taskRun.* /
// client.taskGroup.* directly. Requires NODE_FUNCTION_ALLOW_EXTERNAL=parallel-web
// on self-hosted n8n; n8n Cloud allowlists it for the procurement template.
const ParallelMod = require('parallel-web');
const Parallel = ParallelMod.default || ParallelMod;
const client = new Parallel({ apiKey: $vars.PARALLEL_API_KEY });

const runId = $json.run_id;
if (!runId) throw new Error('AdHoc: Fetch Result — missing run_id.');
const result = await client.taskRun.result(runId);
return [{ json: {
  ...$json,
  research_output: result.output && result.output.content,
  basis: (result.output && result.output.basis) || [],
} }];

const input = $input.first().json;
const output = input.research_output || input;
const vendor = input.vendor || {};
const basis = Array.isArray(input.basis) ? input.basis : (Array.isArray(output.basis) ? output.basis : []);

const RISK_ORDER = { LOW: 0, MEDIUM: 1, HIGH: 2, CRITICAL: 3 };
const CONFIDENCE_RANK = { low: 1, medium: 2, high: 3 };
const DIMENSION_KEYS = ['financial_health','legal_regulatory','cybersecurity','leadership_governance','esg_reputation'];

// ── Step 1: severity aggregation ─────────────────────────────────────
const counts = { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0 };
const categories = [];
const mediumCats = [];
for (const dim of DIMENSION_KEYS) {
  const sev = ((output[dim] && output[dim].severity) || 'LOW').toUpperCase();
  counts[sev] = (counts[sev] || 0) + 1;
  if (sev === 'CRITICAL' || sev === 'HIGH') categories.push(dim);
  if (sev === 'MEDIUM') mediumCats.push(dim);
}

// ── Step 2: risk level assignment ────────────────────────────────────
let risk_level, adverse_flag;
if (counts.CRITICAL > 0) { risk_level = 'CRITICAL'; adverse_flag = true; }
else if (counts.HIGH >= 1) { risk_level = 'HIGH'; adverse_flag = true; }
else if (counts.MEDIUM >= 3) { risk_level = 'MEDIUM'; adverse_flag = new Set(mediumCats).size >= 2; }
else if (counts.MEDIUM >= 1) { risk_level = 'MEDIUM'; adverse_flag = false; }
else { risk_level = 'LOW'; adverse_flag = false; }

if (counts.MEDIUM >= 3 && adverse_flag) {
  for (const cat of mediumCats) {
    if (!categories.includes(cat)) categories.push(cat);
  }
}

// ── Step 3: overrides ────────────────────────────────────────────────
const overrides = [];
if (((output.cybersecurity && output.cybersecurity.status) || '').toUpperCase() === 'CRITICAL') {
  if (RISK_ORDER[risk_level] < RISK_ORDER.CRITICAL) risk_level = 'CRITICAL';
  adverse_flag = true;
  overrides.push('active_data_breach');
  if (!categories.includes('cybersecurity')) categories.push('cybersecurity');
}
if (((output.legal_regulatory && output.legal_regulatory.status) || '').toUpperCase() === 'CRITICAL') {
  if (RISK_ORDER[risk_level] < RISK_ORDER.HIGH) risk_level = 'HIGH';
  adverse_flag = true;
  overrides.push('active_government_litigation');
  if (!categories.includes('legal_regulatory')) categories.push('legal_regulatory');
}

// risk_tier_override on the Vendors sheet acts as a FLOOR — never scores below.
const tierOverride = vendor.risk_tier_override || input.risk_tier_override;
if (tierOverride && RISK_ORDER[tierOverride] != null && RISK_ORDER[tierOverride] > RISK_ORDER[risk_level]) {
  risk_level = tierOverride;
  overrides.push('risk_tier_override_' + tierOverride);
}

// ── Step 4: derived fields ───────────────────────────────────────────
const action_required = risk_level === 'HIGH' || risk_level === 'CRITICAL';
const recMap = { LOW: 'continue_monitoring', MEDIUM: 'escalate_review', HIGH: 'initiate_contingency', CRITICAL: 'suspend_relationship' };
const recommendation = recMap[risk_level];
const vendor_name = output.vendor_name || vendor.vendor_name || 'Unknown';
const summary = vendor_name + ' assessed at ' + risk_level + ' risk. ' + (adverse_flag ? 'Adverse conditions detected.' : 'No adverse conditions.');

// ── Step 5: basis plumbing (top citation per triggered dimension) ───
const basisByDim = {};
for (const entry of basis) {
  const field = entry.field || '';
  const dim = DIMENSION_KEYS.find(d => field === d || field.startsWith(d + '.'));
  if (!dim) continue;
  if (!basisByDim[dim]) basisByDim[dim] = [];
  basisByDim[dim].push(entry);
}

const topCitations = [];
for (const dim of categories) {
  const entries = basisByDim[dim];
  if (!entries || entries.length === 0) continue;
  const sorted = entries.slice().sort((a, b) =>
    (CONFIDENCE_RANK[(b.confidence || '').toLowerCase()] || 0) -
    (CONFIDENCE_RANK[(a.confidence || '').toLowerCase()] || 0)
  );
  for (const entry of sorted) {
    const cite = (entry.citations || [])[0];
    if (!cite || !cite.url) continue;
    topCitations.push({
      dimension: dim,
      url: cite.url,
      title: cite.title || null,
      reasoning: entry.reasoning || null,
      confidence: entry.confidence || null,
    });
    break;
  }
  if (topCitations.length >= 3) break;
}
const top = topCitations[0] || null;

return [{
  json: {
    vendor_name, risk_level, adverse_flag, action_required, recommendation,
    summary, categories, severity_counts: counts, triggered_overrides: overrides,
    assessment_date: new Date().toISOString().slice(0, 10),
    source: input.source || 'deep_research',
    run_id: input.run_id || '',
    // Audit-row columns — surface the top citation alongside the existing
    // fields so the row alone answers "why was this flagged".
    top_citation_url: top ? top.url : null,
    top_citation_title: top ? top.title : null,
    confidence: top ? top.confidence : null,
    top_citations: topCitations,
    basis_per_dimension: basisByDim,
  }
}];

const expected = $vars.PROCUREMENT_SNAPSHOT_TOKEN;
if (!expected) {
  throw new Error('snapshot: PROCUREMENT_SNAPSHOT_TOKEN env var is not set. Refusing to serve unauthenticated snapshot.');
}
const query = $json.query || {};
const headers = $json.headers || {};
const presented = query.t || headers['x-procurement-token'] || '';
if (typeof presented !== 'string' || presented.length === 0 || presented.length > 256) {
  throw new Error('snapshot: missing or malformed token');
}
if (presented.length !== expected.length) {
  throw new Error('snapshot: token rejected');
}
let diff = 0;
for (let i = 0; i < expected.length; i++) {
  diff |= expected.charCodeAt(i) ^ presented.charCodeAt(i);
}
if (diff !== 0) {
  throw new Error('snapshot: token rejected');
}
return [{ json: $json }];

const registry = $('Snapshot: Read Registry').all().map(i => i.json);
const audit_log = $('Snapshot: Read Audit Log').all().map(i => i.json);
const monitors = $('Snapshot: Read Monitors').all().map(i => i.json);

return [{
  json: {
    last_updated: new Date().toISOString(),
    registry,
    audit_log,
    monitors,
    counts: {
      vendors: registry.length,
      audits: audit_log.length,
      monitors: monitors.length,
    },
  }
}];
